from source import powerset

def test_powerset_contains_all_subsets_for_two_elements():
    result = powerset([1, 2])
    expected_subsets = {frozenset(), frozenset({1}), frozenset({2}), frozenset({1, 2})}
    result_sets = {frozenset(s) for s in result}
    assert result_sets == expected_subsets, f"Expected powerset([1, 2]) to be {expected_subsets}, got {result_sets}"
